INSERT INTO projekty (slug, nazev, lokalita, cena, poznamka_cena, dispozice, uzitna_plocha, pozemek, energeticka_trida, stav, typ_domu, druh_objektu, stav_domu, realizace, popis, vybava, fotogalerie, pudorys, hlavni_foto, maklerka_jmeno, maklerka_telefon, maklerka_email) VALUES ('mysliborice-rd-samostatny-0012', 'RD 4+kk Myslibořice, samostatně stojící', 'Myslibořice, okres Třebíč', 8300000, 'K ceně se připočítává provize RK 200 000 Kč + DPH.', '4+kk', 128, 640, 'B', 'Volné', 'Přízemní samostatně stojící', 'Dřevostavba', 'Novostavba', '2026', 'Hledáte bydlení v klidné obci s prioritou dojezdového času do Dukovan? Jedná se o výstavbu tří samostatně stojících rodinných domů v Myslibořicích. Dům na rovinatém pozemku 640 m² s užitnou plochou 128 m², obývací pokoj s kuchyní 43 m². Šatna 8,4 m² navazující na ložnici. Výběr mezi moderním a venkovským stylem kuchyně a koupelny. Dům připraven k okamžitému nastěhování.', '{"Tepelné čerpadlo vzduch-voda","Podlahové vytápění","Rekuperace vzduchu","Kuchyňská linka vč. spotřebičů","Koupelna vč. zařizovacích prvků","Šatna 8,4 m² u ložnice","Dřevovláknité izolační desky","Možnost krbových kamen","Výběr moderní / venkovský styl","Zahrada přístupná z obývacího pokoje","Vodovod, kanalizace"}', '{"/images/projekty/nabidka-0012/r-01.jpg","/images/projekty/nabidka-0012/r-02.jpg","/images/projekty/nabidka-0012/r-03.jpg","/images/projekty/nabidka-0012/r-04.jpg","/images/projekty/nabidka-0012/r-05.jpg","/images/projekty/nabidka-0012/r-06.jpg","/images/projekty/nabidka-0012/r-07.jpg","/images/projekty/nabidka-0012/r-08.jpg","/images/projekty/nabidka-0012/1.jpg","/images/projekty/nabidka-0012/2.jpg","/images/projekty/nabidka-0012/3.jpg","/images/projekty/nabidka-0012/4.jpg","/images/projekty/nabidka-0012/5.jpg","/images/projekty/nabidka-0012/7.jpg","/images/projekty/nabidka-0012/7-1.jpg","/images/projekty/nabidka-0012/8.jpg"}', '/images/projekty/nabidka-0012/khb-dsp-d.1.03-pudorys-1.np.jpg', '/images/projekty/nabidka-0012/r-02.jpg', 'Ing. Eli