kova@kkrealhome.cz');
INSERT INTO blog_posts (slug, titulek, datum, autor, kratky_popis, obsah, nahledovy_obrazek, published) VALUES ('drevene-konstrukce-vyhodou-ekologickeho-bydleni', 'Dřevěné konstrukce: Výhodou ekologického bydlení', '2026-03-15', 'Petra Nováková', 'Zjistěte, proč jsou dřevěné skelety nejlepší volbou pro moderní rodinné domy. Rozebíráme ekologické výhody, tepelné vlastnosti a dlouhodobou trvanlivost.', '<h2>Proč si vybrat dřevěný skelet?</h2><p>Dřevěné konstrukce se stávají srdcem moderního stavitelství v České republice. Nejsou to jen nositelé struktury domu - jsou to základem zdravého a udržitelného bydlení. Naší společnosti Konrad Home Build se věnuje péči o kvalitu dřeva a inovativní konstrukční řešení více než patnáct let.</p><p>Dřevo je obnovitelný zdroj, který se regeneruje. Při správné správě lesů je dřevo jedním z nejekologičtějších stavebních materiálů. Navíc, dřevo má vynikající tepelné vlastnosti a přirozeně reguluje vlhkost v místnostech. To znamená lepší komfort a nižší náklady na vytápění a chlazení.</p><h2>Tepelné vlastnosti a energetická účinnost</h2><p>Moderní dřevěné domy postavené technikou dřevěného skeletu dosahují třídy A+ energetické účinnosti. To je výsledek kvalitní izolace a vzduchotěsnosti. Typický rodinný dům z našeho portfolia spotřebuje méně než 40 kWh/m² za rok, což je polovinou průměrné spotřeby klasických domů.</p><p>Dřevo je přirozeným izolátorem. Má nižší tepelnou vodivost než beton, což znamená, že lépe zadrží teplo v zimě a chází jej v létě. To vede ke značným úsporám na energiích během celého roku.</p><h2>Kvalita a trvanlivost</h2><p>Pokud je dřevo správně ochrněno a stavba je kvalitně provedena, dřevěný dům může vydržet více než 150 let. Naše stavby jsou realizovány s nejpřísnějšími standardy a používáme jen certifikované materiály. Každá stavba prochází detailní kontrolou v každé fázi výstavby.</p><p>Investice do dřevěného domu je investicí do budoucnosti vaší rodiny a planety.</p>', '/images/blog/drevo-konstrukce-nahled.jpg', true);
INSERT INTO blog_posts (slug, titulek, datum, autor, kratky_popis, obsah, nahledovy_obrazek, published) VALUES ('jak-vybrat-idealny-pozemek-pro-stavbu', 'Jak vybrat ideální pozemek pro stavbu domu', '2026-02-28', 'Petra Nováková', 'Kompletní průvodce výběrem správného pozemku.什么věty klíčové faktory jako orientace, dostupnost inženýrských sítí a stavební podmínky.', '<h2>Orientace a klimatické podmínky</h2><p>Správná orientace pozemku může ušetřit až 30% energie na vytápění. Ideálně by měl dům čelit severu na jedné straně a jihu na straně obytné. Zimní slunce proniká hluboko do domu, zatímco letní slunce je chráněno přesahy střechy. Lokalita v South Moravě nabízí ideální podmínky pro soutěž se sluneční energií.</p><p>Zjistěte si také, jak fouká vítr na vašem místě. Severozápadní větry jsou v České republice nejčastější. Můžete je využít k přirozenému větrání v létě, nebo je blokovat správným umístěním stromů a staveb.</p><h2>Dostupnost inženýrských sítí</h2><p>Před koupí pozemku je nezbytné ověřit si dostupnost vody, kanalizace, elektrické energie a plynu. Pokud některé sítě chybějí, mohou náklady na jejich zajištění výrazně zvýšit cenu stavby. V South Moravě jsou většina pozemků dobře připravena, ale vždy stojí za to dvoukrát zkontrolovat.</p><p>Také zjistěte si, kdo je vlastníkem přípojek a jaké jsou podmínky jejich používání. Někdy je nutno zaplatit tzv. přispěvatelský poplatek.</p><h2>Stavební podmínky a místní předpisy</h2><p>Přesvědčte se, že pozemek je stavebně vhodný. Není všechno stavitelné. Některé pozemky jsou v chráněných oblastech, některé jsou zatopeny nebo nemají právní přístup. Vždy si nechte pozemek prověřit stavbyvedoucím nebo architektem, který má zkušenosti s lokalitou.</p><p>Naše společnost Konrad Home Build vám rád pomůže s výběrem pozemku a posouzením jeho vhodnosti pro vaši stavbu. Máme rozsáhlou zkušenost s South Moravskými lokalitami a víme, co má smysl a co nikoli.</p>', '/images/blog/pozemek-vybor-nahled.jpg', true);
INSERT INTO blog_posts (slug, titulek, datum, autor, kratky_popis, obsah, nahledovy_obrazek, published) VALUES ('trendy-v-designu-modernich-rodinnych-domu', 'Trendy v designu moderních rodinných domů 2026', '2026-02-10', 'Petra Nováková', 'Poznámkový přehled posledních designových trendů v stavbě domů. Od otevřených prostor až po integraci chytrých domácích technologií.', '<h2>Otevřené prostory a flexibilní řešení</h2><p>Trend otevřených prostorů bez zbytečných dělících stěn pokračuje. Moderní rodiny si přejí, aby obývací pokoj, jídelna a kuchyň tvořily jednu spojitou zónu. To umožňuje lepší dozor nad dětmi, lepší sociální interakci a lepší využití světla.</p><p>Zároveň si lidé přejí flexibilní řešení - místnosti, které lze při potřebě rozdělit posuvnými dveřmi nebo lehkými přepážkami. To je obzvlášť důležité, když se pracuje z domova.</p><h2>Chytré domácnosti a automatizace</h2><p>Inteligentní řídicí systémy nejsou již luxusem, ale nutností. Moderní domácnosti se řídí pomocí aplikací v telefonu. Vytápění, osvětlení, bezpečnost a spotřebiče mohou být všechny integrovány do jednoho systému.</p><p>Konrad Home Build nově nabízí předinstalované chytré domácnosti v každém domě. Senzory měří teplotu, vlhkost a přítomnost osob, a systém automaticky upravuje provoz domu pro maximální komfort a účinnost.</p><h2>Outdoor living</h2><p>Terasy a venkovní obytné prostory se staly přirozenou součástí domů. Moderní dům bez terasy je už těžko představitelný. Lidé si přejí využívat venkovní prostor po dobu celého roku - proto jsou populární pergoly s topením, zastřešené terasy a venkovní kuchyňky.</p><p>Naše projekty věnují velkou pozornost návaznosti mezi vnitřními a venkovními prostory. To tvoří harmonických 30-40% zvýšení subjektivního pocitu bydlení.</p><h2>Přírodní materiály a wellness</h2><p>Návrat k přírodě se odráží v designu. Dřevo, přírodní kameny a textilie z přírodních vláken domináním. Lidé si více uvědomují, že čím více přírodních materiálů je okolo nich, tím se lépe cítí a spí.</p><p>Wellness zóny s saunami, vířivkami a relaxačními místnostmi jsou přidané hodnoty, které zvyšují kvalitu života a pohodu v domě.</p>', '/images/blog/trendy-design-nahled.jpg', true);
INSERT INTO site_config (id, nazev_firmy, nazev_kratky, popis, telefon, email, adresa, ico, dic, web, pusobnost, facebook_url, instagram_url, zakladatel_jmeno, zakladatel_pozice, zakladatel_citat, zakladatel_foto, sluzby, partneri) VALUES (1, 'KONRAD HOME BUILD, s.r.o.', 'Konrad Home Build', 'Stavíme moderní dřevostavby na klíč na jižní Moravě. Kvalitní rodinné domy s důrazem na ekologii a energetickou úspornost.', '+420 724 257 621', 'konradbuild@email.cz', 'Suchohrdly u Miroslavi 194, 671 72 Suchohrdly u Miroslavi', '18013015', 'CZ18013015', 'www.konradhomebuild.cz', 'Moravský Krumlov a okolí 50 km', 'https://www.facebook.com/profile.php?id=61553308766659', 'https://www.instagram.com/konrad_home_build/', 'Lubomír Konrad', 'Zakladatel a odborník v oboru stavitelství', 'S Konrad Home Build získáte nejen krásný domov, ale i jistotu kvalitní stavby. S našimi zkušenostmi a odborností jde všechno hladce.', '/images/team/lubomir-konrad.jpg', '{"Dřevostavby na klíč"}', true);
