INSERT INTO reference (jmeno, text, poradi) VALUES ('Petr Opálka', 'Dělali jsme si dřevostavbu na klíč s Lubošem Konrádem a nemohli být šťastnější. Jejich skvělý tým nám naslouchal, pochopil naše přání a s velkým nadšením nám postavil náš vysněný dům. Od začátku až do konce byla komunikace a profesionalita bezchybná.', 0);
INSERT INTO reference (jmeno, text, poradi) VALUES ('Oldřich Hrb', 'Jsme nadšeni spoluprací při kompletní rekonstrukci našeho domu. Od samého začátku až do konce bylo naše zkušenost s touto stavební firmou naprosto pozitivní. Předvedli odbornost, profesionalitu a důraz na kvalitu v každém detailu projektu.', 1);
INSERT INTO reference (jmeno, text, poradi) VALUES ('Kamila Kolesová', 'Spolupráce s Lubošem Konrad byla úžasná. Postavili nám dřevostavbu s použitím skvělých materiálů. Profesionální přístup a kvalitní práce nás nadchly. Doporučujeme je vřele!', 2);
